select periodo,             rucEntidad,             cta_mayor_pagar_cobrar,             sum(flujo_deudor)    as flujo_deudor,             sum(flujo_acreedor)  as flujo_acreedor,             ruc,             nombre_tepro,             codigo_clasificador_prcla,             cta_mayor_gasto_i,             sum(flujo_deudor2)   as flujo_deudor2,             sum(flujo_acreedor2) as flujo_acreedor2,             max(nro_transaccion) as nro_transaccion,             max(nro_referenci)   as nro_referenci,             fecha_apro,             fecha_venc      from (select extract(month from mov.mov_fecha_comov)                                            as periodo,                   (select identificacion_empr from sis_empresa)                                      as rucEntidad,                   dmovi.cue_codigo_cocac                                                             as cta_mayor_pagar_cobrar,                   dmovi.haber_codem                                                                  as flujo_deudor,                   dmovi.debe_codem                                                                   as flujo_acreedor,                   (case when cp.ide_geedp is null then prov.ruc_tepro else '9999999999999' end)      as ruc,                   (case when cp.ide_geedp is null then prov.nombre_tepro else 'VARIOS CLIENTES' end) as nombre_tepro                    ,                   cast('' as character(25))                                                          as codigo_clasificador_prcla                    ,                   cast('111.06.00' as character(25))                                                 as cta_mayor_gasto_i                    ,                   0                                                                                  as flujo_deudor2                    ,                   coalesce(dmovi.haber_codem, 0)                                                     as flujo_acreedor2                    ,                   coalesce(cast(comprobante_egreso_tecpo as bigint), mov.ide_comov)                  as nro_transaccion                    ,                   coalesce(cast(comprobante_egreso_tecpo as bigint), mov.ide_comov)                  as nro_referenci                    ,                   cast('2025-01-01' as character(25))                                         as fecha_apro,                   cast('2025-11-30' as character(25))                                           as fecha_venc            from cont_movimiento mov                     left join tes_comprobante_pago cp on cp.ide_tecpo = mov.ide_tecpo                     left join (select b.ide_tepro,                                       coalesce(ruc_representante_tepro, ruc_tepro) as ruc_tepro,                                       substring(nombre_tepro from 1 for 30)        as nombre_tepro                                from tes_proveedor b) prov on prov.ide_tepro = cp.ide_tepro                     join (select dmov.ide_comov, ide_gelua, cue_codigo_cocac, dmov.debe_codem, dmov.haber_codem                           from cont_detalle_movimiento dmov                                    join cont_catalogo_cuenta cat                                         on cat.ide_cocac = dmov.ide_cocac and cue_codigo_cocac like '112.01%'                           where sigef_cocac = true                             and nivel_cocac = 4) dmovi on dmovi.ide_comov = mov.ide_comov            where mov.mov_fecha_comov between '2025-01-01' and '2025-11-30') a      group by periodo, rucEntidad, cta_mayor_pagar_cobrar, ruc, nombre_tepro, codigo_clasificador_prcla, cta_mayor_gasto_i,               fecha_apro, fecha_venc  

